   598→// Analyze speech transcription for communication quality
   599→function analyzeSpeechPatterns(transcription, durationSeconds) {
   600→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   601→  const wordCount = words.length;
   602→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   603→
   604→  // Filler word detection
   605→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   606→  const fillerCounts = {};
   607→  let totalFillers = 0;
   608→  const lowerTranscription = transcription.toLowerCase();
   609→
   610→  for (const filler of fillerWords) {
   611→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   612→    const matches = lowerTranscription.match(regex);
   613→    if (matches && matches.length > 0) {
   614→      fillerCounts[filler] = matches.length;
   615→      totalFillers += matches.length;
   616→    }
   617→  }
   618→
   619→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   620→
   621→  // Pace analysis
   622→  let paceAssessment = 'good';
   623→  let paceFeedback = '';
   624→  if (wpm < 100) {
   625→    paceAssessment = 'too_slow';
   626→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   627→  } else if (wpm < 120) {
   628→    paceAssessment = 'slightly_slow';
   629→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   630→  } else if (wpm <= 160) {
   631→    paceAssessment = 'good';
   632→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   633→  } else if (wpm <= 180) {
   634→    paceAssessment = 'slightly_fast';
   635→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   636→  } else {
   637→    paceAssessment = 'too_fast';
   638→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   639→  }
   640→
   641→  // Sentence structure analysis
   642→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   643→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   644→
   645→  // Communication score (1-10)
   646→  let communicationScore = 7;
   647→  // Penalize for filler words
   648→  if (fillerRate > 5) communicationScore -= 2;
   649→  else if (fillerRate > 3) communicationScore -= 1;
   650→  // Penalize for bad pace
   651→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   652→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   653→  // Reward for good sentence structure
   654→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   655→  // Penalize for very short responses
   656→  if (wordCount < 50) communicationScore -= 2;
   657→  else if (wordCount < 100) communicationScore -= 1;
   658→  // Reward for substantial responses
   659→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   660→
   661→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   662→
   663→  return {
   664→    word_count: wordCount,
   665→    duration_seconds: durationSeconds,
   666→    words_per_minute: wpm,
   667→    filler_words: fillerCounts,
   668→    total_fillers: totalFillers,
   669→    filler_rate: Math.round(fillerRate * 10) / 10,
   670→    pace: {
   671→      assessment: paceAssessment,
   672→      wpm,
   673→      feedback: paceFeedback
   674→    },
   675→    sentence_count: sentences.length,
   676→    avg_sentence_length: avgSentenceLength,
   677→    communication_score: communicationScore,
   678→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   679→  };
   680→}
   681→
   682→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   683→  const tips = [];
   684→
   685→  if (fillerRate > 3) {
   686→    const topFillers = Object.entries(fillerCounts)
   687→      .sort((a, b) => b[1] - a[1])
   688→      .slice(0, 3)
   689→      .map(([word, count]) => `"${word}" (${count}x)`);
   690→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   691→  }
   692→
   693→  if (wpm > 160) {
   694→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   695→  } else if (wpm < 110) {
   696→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   697→  }
   698→
   699→  if (wordCount < 80) {
   700→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   701→  }
   702→
   703→  if (tips.length === 0) {
   704→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   705→  }
   706→
   707→  return tips;
   708→}
